        },
        {
            "status": "actionable_context",
            "note": "Given FOXM1 is a nuclear human transcription factor, direct antibody complex structures may be sparse; if present, they are more likely to target the forkhead DNA-binding domain or peptide epitopes from cancer studies."
        }
    ],
    "iedb_hits": [
        {
            "status": "not_retrieved",
            "note": "No IEDB query tool was available in the current environment, so I could not directly extract experimentally validated epitopes."
        },
        {
            "status": "actionable_context",
            "note": "FOXM1 is self-antigen-like and intracellular; T-cell epitopes reported in IEDB, if any, are likely cancer/immunology-focused rather than neutralizing extracellular epitopes."
        }
