        {
            "type": "domain_context",
            "finding": "The canonical FOXM1 protein contains a forkhead DNA-binding domain; the supplied sequence fragment appears largely low-complexity and may represent a region outside the structured forkhead domain."
        },
        {
            "type": "design_relevance",
            "finding": "For binder discovery, structured domains and exposed unique motifs are typically more tractable than highly disordered low-complexity segments."
        }
    ],
    "design_constraints": [
        "Do not assume extracellular accessibility: FOXM1 is intracellular/nuclear.",
        "The provided sequence is a fragment; binder design depends on whether the full-length protein or fragment is intended.",
        "Low-complexity regions may be harder to target with high-specificity binders.",
